mapper.select:
select f.`code`, f.`name`, f.type, f.domain, f.path, f.suffix, concat(#{localFilePath,jdbcType=VARCHAR}, f.code) as url, f.source, f.size, f.create_time, u.nickname as create_by, f.sync_directory_id as syncDirectoryId, f.relative_path as relativePath, COALESCE(f.update_time, f.create_time) as lastSyncTime from file f left join `user` u on f.create_by = u.id
and f.type = #{param.type,jdbcType=INTEGER}
AND f.name LIKE CONCAT('%',#{param.name,jdbcType=VARCHAR},'%')
and f.source = #{param.source,jdbcType=INTEGER}
AND f.create_by = #{param.userId,jdbcType=INTEGER}
AND f.sync_directory_id = #{param.syncDirectoryId,jdbcType=BIGINT}
AND (f.relative_path IS NULL OR f.relative_path = '' OR f.relative_path NOT LIKE '%/%')
AND (f.relative_path = #{param.relativePath,jdbcType=VARCHAR} OR (f.relative_path LIKE CONCAT(#{param.relativePath,jdbcType=VARCHAR}, '/%') AND LOCATE('/', f.relative_path, CHAR_LENGTH(#{param.relativePath,jdbcType=VARCHAR})+2)=0))
and f.del_flag = 0
order by COALESCE(f.update_time, f.create_time) desc

SELECT DISTINCT f.sync_directory_id as syncDirectoryId, f.relative_path as relativePath FROM file f WHERE f.del_flag = 0 AND f.sync_directory_id IN
#{id}
AND f.relative_path IS NOT NULL AND f.relative_path != ''
